INSERT INTO `blogs` (`id`, `slug`, `title`, `category_id`, `excerpt`, `author_id`, `guest_author_name`, `reading_time`, `publish_date`, `seo_title`, `seo_description`, `featured_image_id`, `status`, `created_at`, `updated_at`) VALUES
('1', 'private-limited-company-registration', 'Steps to Register a Private Limited Company in India', '1', 'A comprehensive step-by-step guide to incorporating your Private Limited company in India, including name approval, digital signatures, SPICe+ form submissions, and post-incorporation setup.', NULL, 'Aum Jani', '8 min read', '2026-05-28', 'How to Register a Private Limited Company in India - Step-by-Step Guide', 'Learn how to register a Private Limited (Pvt Ltd) Company in India. A complete guide on eligibility, required documents, MCA SPICe+ process, and compliance steps.', '1', 'published', '2026-05-28 10:00:00', '2026-06-06 10:41:55'),
('2', 'annual-roc-filing-requirements', 'Annual ROC Filing Requirements Explained', '2', 'An in-depth guide on mandatory annual compliance, ROC filings, important e-forms like AOC-4 and MGT-7, deadlines, and the cost of non-compliance for Indian companies.', '2', NULL, '10 min read', '2026-05-24', 'Annual ROC Filing Requirements & Deadlines for Indian Companies', 'Understand the annual ROC filing requirements for Private Limited Companies. Learn about AOC-4, MGT-7, deadlines, penalties, and best compliance practices.', '2', 'published', '2026-05-24 10:00:00', '2026-05-24 10:00:00'),
('3', 'startup-india-registration-benefits', 'Startup India Registration Benefits for New Businesses', '3', 'Learn how the Startup India Scheme benefits early-stage ventures. Discover eligibility criteria, 3-year tax exemptions, patent cost rebates, funding options, and the application process.', NULL, NULL, '7 min read', '2026-05-15', 'Startup India Registration Benefits, Eligibility & Application', 'Unlock tax holidays, patent rebates, and easy compliance by securing Startup India recognition. Explore the complete guide on eligibility and application steps.', '3', 'published', '2026-05-15 10:00:00', '2026-05-15 10:00:00'),
('5', 'test', 'TEST', '2', 'TEST', '2', NULL, '6 min read', '2026-06-06', 'TEST', 'TEST', '17', 'published', '2026-06-06 12:52:55', '2026-06-06 14:32:00');
INSERT INTO `blog_content_blocks` (`id`, `blog_id`, `block_type`, `sort_order`, `text_content`, `image_id`, `block_data`, `created_at`, `updated_at`) VALUES
('30', '2', 'paragraph', '1', 'Every registered corporate entity in India, regardless of its turnover, profit margin, or activity status, has a mandatory obligation to file annual returns with the Registrar of Companies (ROC). The ROC, operating under the Ministry of Corporate Affairs (MCA), oversees corporate compliance. Failing to meet these statutory deadlines results in severe penalties, disqualification of directors, and active company lockouts. This article breaks down the essential forms, filing timelines, and mandatory annual compliances for Private Limited Companies.', NULL, NULL, '2026-05-24 10:05:00', '2026-05-24 10:05:00'),
('31', '2', 'heading2', '2', 'What is ROC Filing?', NULL, NULL, '2026-05-24 10:05:01', '2026-05-24 10:05:01'),
('32', '2', 'paragraph', '3', 'ROC filing refers to the submission of structured financial reports, shareholder lists, director disclosures, and general meeting updates to the Registrar of Companies. These filings are submitted annually under the provisions of the Companies Act, 2013. The main objective is to maintain corporate transparency and ensure that the government, investors, and public stakeholders have access to updated corporate statistics.', NULL, NULL, '2026-05-24 10:05:02', '2026-05-24 10:05:02'),
('33', '2', 'heading2', '4', 'Who Must File?', NULL, NULL, '2026-05-24 10:05:03', '2026-05-24 10:05:03'),
('34', '2', 'paragraph', '5', 'Every company incorporated under the Companies Act (including Private Limited Companies, Public Limited Companies, One Person Companies, and Section 8 companies) must complete these filings. This rule applies even if the company:', NULL, NULL, '2026-05-24 10:05:04', '2026-05-24 10:05:04'),
('35', '2', 'bullet-list', '6', NULL, NULL, '{\"items\": [\"Has not conducted any business activity during the financial year.\", \"Has registered zero turnover and zero transaction volumes.\", \"Is operating at a financial loss.\"]}', '2026-05-24 10:05:05', '2026-05-24 10:05:05'),
('36', '2', 'heading2', '7', 'Important ROC Forms and Submissions', NULL, NULL, '2026-05-24 10:05:06', '2026-05-24 10:05:06'),
('37', '2', 'paragraph', '8', 'The annual compliance framework involves multiple specialized forms, each catering to a distinct reporting requirement:', NULL, NULL, '2026-05-24 10:05:07', '2026-05-24 10:05:07'),
('38', '2', 'table', '9', NULL, NULL, '{\"rows\": [[\"AOC-4\", \"Filing of Audited Financial Statements (Balance Sheet, P&L, Auditor Report)\", \"Within 30 days of the AGM\"], [\"MGT-7\", \"Filing of Annual Return (Shareholding pattern, director info, details of debt/shares)\", \"Within 60 days of the AGM\"], [\"DIR-3 KYC\", \"Director KYC Verification (Confirmation of phone number and email ID of each DIN holder)\", \"Annually by 30th September\"], [\"ADT-1\", \"Notice of Appointment of Statutory Auditor (For a block of 5 years)\", \"Once in 5 years (within 15 days of AGM)\"], [\"MSME Form I\", \"Disclosure of outstanding payments to MSME suppliers (For delays over 45 days)\", \"Half-yearly (April 30 & October 31)\"]], \"headers\": [\"Form Name\", \"Filing Purpose\", \"Filing Frequency\"]}', '2026-05-24 10:05:08', '2026-05-24 10:05:08'),
('39', '2', 'heading2', '10', 'Filing Deadlines and the Annual Calendar', NULL, NULL, '2026-05-24 10:05:09', '2026-05-24 10:05:09'),
('40', '2', 'paragraph', '11', 'ROC filing deadlines are directly linked to the date of the Annual General Meeting (AGM). The standard compliance timeline follows this sequence:', NULL, NULL, '2026-05-24 10:05:10', '2026-05-24 10:05:10'),
('41', '2', 'numbered-list', '12', NULL, NULL, '{\"items\": [\"Closing of Accounts: The financial year ends on March 31st. All accounts must be finalized and audited.\", \"Board Meeting: A board meeting is held to approve the audited financial statements and draft the Director\'s Report.\", \"Annual General Meeting (AGM): The company must hold its AGM on or before September 30th (within 6 months from the closing of the financial year).\", \"Form AOC-4 Submission: File audited accounts within 30 days of the AGM (typically by October 30th).\", \"Form MGT-7 Submission: File the annual return within 60 days of the AGM (typically by November 29th).\"]}', '2026-05-24 10:05:11', '2026-05-24 10:05:11'),
('42', '2', 'highlight-box', '13', 'Note: For newly incorporated companies, if the incorporation date falls between January 1st and March 31st, the company can choose to close its first financial year on March 31st of the following calendar year. In this case, the first AGM must be held within 9 months from the end of that financial year.', NULL, NULL, '2026-05-24 10:05:12', '2026-05-24 10:05:12'),
('43', '2', 'heading2', '14', 'Penalties for Non-Compliance', NULL, NULL, '2026-05-24 10:05:13', '2026-05-24 10:05:13'),
('44', '2', 'paragraph', '15', 'The MCA has significantly raised the cost of corporate defaults. Failing to file AOC-4 or MGT-7 attracts the following penalties:', NULL, NULL, '2026-05-24 10:05:14', '2026-05-24 10:05:14'),
('45', '2', 'bullet-list', '16', NULL, NULL, '{\"items\": [\"Late Fees: A statutory penalty of ₹100 per day per form is charged for every day of delay, with no upper cap.\", \"Director Disqualification: If a company fails to file its financial statements or annual returns for three consecutive years, its directors are disqualified for 5 years and their DINs are deactivated.\", \"Striking Off: The Registrar of Companies can strike off the company\'s name from the official register if it finds that the company has not commenced operations or completed filings within 2 years of incorporation.\"]}', '2026-05-24 10:05:15', '2026-05-24 10:05:15'),
('46', '2', 'heading2', '17', 'Best Practices for Timely Compliance', NULL, NULL, '2026-05-24 10:05:16', '2026-05-24 10:05:16'),
('47', '2', 'paragraph', '18', 'To avoid last-minute rush, server delays on the MCA portal, and heavy default fees, businesses should adopt these management practices:', NULL, NULL, '2026-05-24 10:05:17', '2026-05-24 10:05:17'),
('48', '2', 'bullet-list', '19', NULL, NULL, '{\"items\": [\"Close accounts immediately by May 31st and initiate statutory auditing in June.\", \"Maintain clear registers of members, share transfers, and board meetings throughout the year.\", \"Set automatic alert triggers for DIR-3 KYC (due September 30th) and MCA portal updates.\", \"Work with a dedicated compliance advisor who monitors filing status proactively.\"]}', '2026-05-24 10:05:18', '2026-05-24 10:05:18'),
('49', '2', 'heading2', '20', 'Conclusion', NULL, NULL, '2026-05-24 10:05:19', '2026-05-24 10:05:19'),
('50', '2', 'paragraph', '21', 'Annual ROC compliance is a critical governance duty that ensures corporate legitimacy. The penalties for defaults are heavy and can cause serious reputation damage and operational disruption. Keeping a close watch on the corporate calendar, holding board meetings and AGMs on time, and filing digital forms like AOC-4 and MGT-7 before deadlines is essential for clean business operations. Relying on professional corporate services helps you manage these compliance milestones effortlessly.', NULL, NULL, '2026-05-24 10:05:20', '2026-05-24 10:05:20'),
('51', '3', 'paragraph', '1', 'The Startup India Initiative, launched by the Government of India under the Department for Promotion of Industry and Internal Trade (DPIIT), is designed to foster innovation, create jobs, and build a strong startup ecosystem. For early-stage companies, obtaining DPIIT recognition unlocks a wide range of regulatory relaxations, financial rebates, and tax benefits. In this article, we explain the key benefits of Startup India registration, who is eligible, and how to apply.', NULL, NULL, '2026-05-15 10:05:00', '2026-05-15 10:05:00'),
('52', '3', 'heading2', '2', 'Overview of Startup India', NULL, NULL, '2026-05-15 10:05:01', '2026-05-15 10:05:01'),
('53', '3', 'paragraph', '3', 'Launched in 2016, the Startup India scheme aims to simplify operations for startups by reducing bureaucratic hurdles. DPIIT recognition turns your business into a recognized startup under government policy, opening doors to direct state funding, intellectual property facilitation, and tax exemptions.', NULL, NULL, '2026-05-15 10:05:02', '2026-05-15 10:05:02'),
('54', '3', 'heading2', '4', 'Eligibility Criteria for DPIIT Recognition', NULL, NULL, '2026-05-15 10:05:03', '2026-05-15 10:05:03'),
('55', '3', 'paragraph', '5', 'To qualify for DPIIT recognition, a business entity must satisfy the following statutory conditions:', NULL, NULL, '2026-05-15 10:05:04', '2026-05-15 10:05:04'),
('56', '3', 'numbered-list', '6', NULL, NULL, '{\"items\": [\"Entity Type: Must be registered as a Private Limited Company, a Limited Liability Partnership (LLP), or a Registered Partnership Firm.\", \"Company Age: The period of existence must not exceed 10 years from the date of incorporation.\", \"Turnover Limit: The annual turnover must not have exceeded ₹100 crores in any of the preceding financial years.\", \"Original Entity: The startup must not be formed by splitting up or reconstructing an existing business structure.\", \"Innovation Focus: The business model must show potential for innovation, development, or improvement of products, processes, or services, or have a scalable model for wealth and job creation.\"]}', '2026-05-15 10:05:05', '2026-05-15 10:05:05'),
('57', '3', 'heading2', '7', 'Key Benefits of Startup India Registration', NULL, NULL, '2026-05-15 10:05:06', '2026-05-15 10:05:06'),
('58', '3', 'paragraph', '8', 'Once recognized, startups can access multiple strategic advantages that ease cash flow challenges and simplify regulatory filings:', NULL, NULL, '2026-05-15 10:05:07', '2026-05-15 10:05:07'),
('59', '3', 'bullet-list', '9', NULL, NULL, '{\"items\": [\"Self-Certification: Startups can self-certify compliance under 6 labor laws and 3 environmental laws, with zero inspections conducted during the first 3 to 5 years.\", \"Intellectual Property (IPR) Support: Fast-tracked patent applications and up to an 80% rebate on patent filing fees, along with a 50% rebate on trademark filings.\", \"Easy Winding Up: Under the Insolvency and Bankruptcy Code, recognized startups can wind up operations within 90 days (compared to the standard 180 days for other entities).\", \"Public Procurement Advantages: Exemption from paying earnest money deposits (EMD) and meeting prior turnover/experience criteria when bidding for government tenders.\"]}', '2026-05-15 10:05:08', '2026-05-15 10:05:08'),
('60', '3', 'heading2', '10', 'Tax Advantages for Recognized Startups', NULL, NULL, '2026-05-15 10:05:09', '2026-05-15 10:05:09'),
('61', '3', 'paragraph', '11', 'The financial benefits are highly lucrative, offering exemption paths under different sections of the Income Tax Act:', NULL, NULL, '2026-05-15 10:05:10', '2026-05-15 10:05:10'),
('62', '3', 'heading3', '12', 'Section 80-IAC: 3-Year Tax Holiday', NULL, NULL, '2026-05-15 10:05:11', '2026-05-15 10:05:11'),
('63', '3', 'paragraph', '13', 'Eligible startups can apply for a 100% tax exemption on profits for 3 consecutive financial years out of their first 10 years of operations. (Requires additional approval from the Inter-Ministerial Board).', NULL, NULL, '2026-05-15 10:05:12', '2026-05-15 10:05:12'),
('64', '3', 'heading3', '14', 'Section 56(2)(viib): Angel Tax Exemption', NULL, NULL, '2026-05-15 10:05:13', '2026-05-15 10:05:13'),
('65', '3', 'paragraph', '15', 'DPIIT-recognized startups are exempt from tax on share premiums received from investors, even if the share issue price exceeds the fair market value of the shares.', NULL, NULL, '2026-05-15 10:05:14', '2026-05-15 10:05:14'),
('66', '3', 'highlight-box', '16', 'Important: While DPIIT recognition is immediate upon application approval, the 3-year tax holiday under Section 80-IAC requires a separate application to and approval from the Inter-Ministerial Board (IMB).', NULL, NULL, '2026-05-15 10:05:15', '2026-05-15 10:05:15'),
('67', '3', 'heading2', '17', 'Funding Opportunities', NULL, NULL, '2026-05-15 10:05:16', '2026-05-15 10:05:16'),
('68', '3', 'paragraph', '18', 'The government has set up specialized funding mechanisms to help early-stage ventures secure capital:', NULL, NULL, '2026-05-15 10:05:17', '2026-05-15 10:05:17'),
('69', '3', 'bullet-list', '19', NULL, NULL, '{\"items\": [\"Startup India Seed Fund Scheme (SISFS): Provides grants up to ₹20 lakhs for proof of concept/prototype development, and up to ₹50 lakhs in debt/convertible debentures for commercialization.\", \"Fund of Funds for Startups (FFS): A ₹10,000 crore capital corpus managed by SIDBI to invest in venture funds that back high-growth startups.\", \"Credit Guarantee Scheme: Offers credit guarantees to cover collateral-free loans extended by commercial banks and financial institutions to recognized startups.\"]}', '2026-05-15 10:05:18', '2026-05-15 10:05:18'),
('70', '3', 'heading2', '20', 'The Application Process', NULL, NULL, '2026-05-15 10:05:19', '2026-05-15 10:05:19'),
('71', '3', 'paragraph', '21', 'The application is completed entirely online via the Startup India portal. Here is how to apply:', NULL, NULL, '2026-05-15 10:05:20', '2026-05-15 10:05:20'),
('72', '3', 'numbered-list', '22', NULL, NULL, '{\"items\": [\"Create a profile on the Startup India website (www.startupindia.gov.in).\", \"Fill out the Recognition Application Form with entity details, director info, and address details.\", \"Submit a brief write-up explaining your business model, how it is innovative, what problem it solves, and how it plans to create jobs/wealth.\", \"Upload support documents: Certificate of Incorporation (CoI), PAN card, write-up, and optional pitch deck or patent documents.\", \"Submit and track application. Once reviewed and approved by DPIIT, a digital Certificate of Recognition is issued.\"]}', '2026-05-15 10:05:21', '2026-05-15 10:05:21'),
('73', '3', 'heading2', '23', 'Conclusion', NULL, NULL, '2026-05-15 10:05:22', '2026-05-15 10:05:22'),
('74', '3', 'paragraph', '24', 'The Startup India Scheme provides a powerful push for new businesses in India. From 3-year income tax holidays and angel tax exemptions to heavy rebates on trademark and patent applications, the benefits are designed to preserve capital and ease regulatory filings. For any incorporated private limited company or LLP in its early stages, applying for DPIIT recognition is a highly recommended strategic step to accelerate growth and credibility.', NULL, NULL, '2026-05-15 10:05:23', '2026-05-15 10:05:23'),
('104', '1', 'paragraph', '1', 'Registering a Private Limited Company is one of the most popular and structured paths for startups and businesses looking to scale in India. With benefits like limited liability, independent legal existence, and easy access to institutional funding, it offers a robust corporate architecture. However, navigating the legal procedures at the Ministry of Corporate Affairs (MCA) requires a clear understanding of the steps involved. In this comprehensive guide, we walk you through the entire process of incorporating a Private Limited Company from scratch.', NULL, NULL, '2026-06-06 10:41:55', '2026-06-06 10:41:55'),
('105', '1', 'heading2', '2', 'What is a Private Limited Company?', NULL, NULL, '2026-06-06 10:41:55', '2026-06-06 10:41:55'),
('106', '1', 'paragraph', '3', 'A Private Limited (Pvt Ltd) Company is a privately held business entity governed by the Companies Act, 2013. Its ownership is divided into shares, which are held by its shareholders. One of the key characteristics of this structure is that the liability of each shareholder is limited to the nominal value of the shares subscribed by them. Furthermore, the shares cannot be publicly traded, ensuring that the control of the company remains within a closed group of promoters.', NULL, NULL, '2026-06-06 10:41:55', '2026-06-06 10:41:55'),
('107', '1', 'quote', '4', 'A Private Limited Company has a perpetual succession, meaning the business continues to exist legally even if directors or shareholders change, transfer shares, or pass away.', NULL, '{\"author\":\"Pranav Singhania, Co-Founder\"}', '2026-06-06 10:41:55', '2026-06-06 10:41:55'),
('108', '1', 'heading2', '5', 'Benefits of Registration', NULL, NULL, '2026-06-06 10:41:55', '2026-06-06 10:41:55'),
('109', '1', 'paragraph', '6', 'Choosing a Private Limited structure offers several legal and business advantages over partnerships or sole proprietorships:', NULL, NULL, '2026-06-06 10:41:55', '2026-06-06 10:41:55'),
('110', '1', 'bullet-list', '7', NULL, NULL, '{\"items\":[\"Limited Liability Protection: Your personal assets are completely safe from business debts and legal liabilities.\",\"High Credibility: Financial institutions, banks, and prospective clients view registered companies with higher trust.\",\"Easy Funding Attraction: Venture Capitalists (VCs) and Angel Investors prefer investing in Private Limited entities due to the clear share allocation mechanism.\",\"Dual Ownership and Management Role: Promoters can act as shareholders (owners) and directors (managers) concurrently.\"]}', '2026-06-06 10:41:55', '2026-06-06 10:41:55'),
('111', '1', 'heading2', '8', 'Eligibility Requirements', NULL, NULL, '2026-06-06 10:41:55', '2026-06-06 10:41:55'),
('112', '1', 'paragraph', '9', 'Before initiating the registration process, you must ensure that your team satisfies the minimum statutory criteria laid down by the MCA:', NULL, NULL, '2026-06-06 10:41:55', '2026-06-06 10:41:55'),
('113', '1', 'numbered-list', '10', NULL, NULL, '{\"items\":[\"Minimum of two shareholders (individual or corporate entities) and a maximum of 200.\",\"Minimum of two directors. At least one of the directors must be a resident of India (i.e., stayed in India for at least 182 days in the previous financial year).\",\"A registered physical office address within India to receive official communications.\",\"No minimum paid-up capital requirement under the current provisions (you can start with a nominal capital like \\u20b910,000).\"]}', '2026-06-06 10:41:55', '2026-06-06 10:41:55'),
('114', '1', 'heading2', '11', 'Required Documents for Incorporation', NULL, NULL, '2026-06-06 10:41:55', '2026-06-06 10:41:55'),
('115', '1', 'paragraph', '12', 'To ensure a smooth filing experience, promoters must compile clear digital scans of the following personal and address credentials:', NULL, NULL, '2026-06-06 10:41:55', '2026-06-06 10:41:55'),
('116', '1', 'table', '13', NULL, NULL, '{\"headers\":[\"Document Category\",\"For Indian Promoters\",\"For Foreign Promoters\"],\"rows\":[[\"Identity Proof\",\"PAN Card (Mandatory) & Aadhaar Card\",\"Apostilled Passport\"],[\"Address Proof\",\"Bank Statement \\/ Telephone \\/ Electricity Bill (Not older than 2 months)\",\"Apostilled Bank Statement or Utility Bill\"],[\"Proof of Registered Office\",\"Utility Bill & No Objection Certificate (NOC) from owner\",\"Not applicable (Must be in India)\"],[\"Photo Proof\",\"Passport Size Photographs\",\"Passport Size Photographs\"]]}', '2026-06-06 10:41:55', '2026-06-06 10:41:55'),
('117', '1', 'heading2', '14', 'Step-by-Step Registration Process', NULL, NULL, '2026-06-06 10:41:55', '2026-06-06 10:41:55'),
('118', '1', 'paragraph', '15', 'The Ministry of Corporate Affairs has consolidated the registration process through the SPICe+ (Simplified Proforma for Incorporating Company Electronically Plus) web form. The process is divided into distinct execution phases:', NULL, NULL, '2026-06-06 10:41:55', '2026-06-06 10:41:55'),
('119', '1', 'heading3', '16', 'Phase 1: Secure Digital Signature Certificates (DSC)', NULL, NULL, '2026-06-06 10:41:55', '2026-06-06 10:41:55'),
('120', '1', 'paragraph', '17', 'Since all MCA submissions are handled electronically, all proposed directors must acquire a Class 3 Digital Signature Certificate. A DSC is used to digitally sign the incorporation forms.', NULL, NULL, '2026-06-06 10:41:55', '2026-06-06 10:41:55'),
('121', '1', 'heading3', '18', 'Phase 2: Name Reservation via SPICe+ Part A', NULL, NULL, '2026-06-06 10:41:55', '2026-06-06 10:41:55'),
('122', '1', 'paragraph', '19', 'Promoters submit up to two unique names in order of preference. The name must be unique, not resemble any existing company or LLP name, and must not violate trademark laws. Once approved, the name is reserved for 20 days.', NULL, NULL, '2026-06-06 10:41:55', '2026-06-06 10:41:55'),
('123', '1', 'heading3', '20', 'Phase 3: Filing SPICe+ Part B & Agile PRO-S', NULL, NULL, '2026-06-06 10:41:55', '2026-06-06 10:41:55'),
('124', '1', 'paragraph', '21', 'This is the core incorporation document where you submit director details, capital structure, and address details. Concurrently, the Agile PRO-S form is filed to obtain GSTIN, ESIC registration, EPFO registration, Professional Tax registration, and open a corporate bank account.', NULL, NULL, '2026-06-06 10:41:55', '2026-06-06 10:41:55'),
('125', '1', 'heading3', '22', 'Phase 4: Drafting MOA & AOA', NULL, NULL, '2026-06-06 10:41:55', '2026-06-06 10:41:55'),
('126', '1', 'paragraph', '23', 'The Memorandum of Association (MOA) defines the company\'s core objectives, and the Articles of Association (AOA) define its internal bylaws. These are submitted as electronic forms (eMOA and eAOA).', NULL, NULL, '2026-06-06 10:41:55', '2026-06-06 10:41:55'),
('127', '1', 'highlight-box', '24', 'Tip: Ensure that your primary business objective in the MOA is written with precise scope, as the company cannot execute any transactions outside the boundaries of its approved objects.', NULL, NULL, '2026-06-06 10:41:55', '2026-06-06 10:41:55'),
('128', '1', 'heading2', '25', 'Post-Registration Compliance', NULL, NULL, '2026-06-06 10:41:55', '2026-06-06 10:41:55'),
('129', '1', 'paragraph', '26', 'After receiving the Certificate of Incorporation (CoI) and Corporate Identity Number (CIN), you must execute these immediate compliance requirements before commencing business operations:', NULL, NULL, '2026-06-06 10:41:55', '2026-06-06 10:41:55'),
('130', '1', 'bullet-list', '27', NULL, NULL, '{\"items\":[\"Open a corporate bank account in the name of the company using the COI, PAN, and AOA documents.\",\"Deposit Share Capital: Shareholders must deposit their agreed subscription amount into the company account within 180 days.\",\"File Commencement of Business (Form INC-20A) with the ROC within 180 days of incorporation.\",\"Appoint First Auditor: The Board of Directors must appoint a practicing Chartered Accountant as the statutory auditor within 30 days of registration.\"]}', '2026-06-06 10:41:55', '2026-06-06 10:41:55'),
('131', '1', 'heading2', '28', 'Conclusion', NULL, NULL, '2026-06-06 10:41:55', '2026-06-06 10:41:55'),
('132', '1', 'paragraph', '29', 'Registering a Private Limited Company provides a structured, highly credible, and scalable foundation for your business. While the SPICe+ portal has simplified the digital application workflow, drafting the MOA, AOA, and navigating name queries requires specialized oversight. Partnering with professional company secretaries and Chartered Accountants ensures a hassle-free, legally compliant setup, allowing you to focus on growing your venture.', NULL, NULL, '2026-06-06 10:41:55', '2026-06-06 10:41:55'),
('215', '5', 'paragraph', '1', 'Write your introductory paragraph here to engage the reader and summarize the compliance discussion.', NULL, NULL, '2026-06-06 14:32:00', '2026-06-06 14:32:00'),
('216', '5', 'heading2', '2', 'What is the Core Concept?', NULL, NULL, '2026-06-06 14:32:00', '2026-06-06 14:32:00'),
('217', '5', 'paragraph', '3', 'Explain the central concept, its definition under legal frameworks, and why it is critical for business promoters.', NULL, NULL, '2026-06-06 14:32:00', '2026-06-06 14:32:00'),
('218', '5', 'image', '4', NULL, '17', '{\"caption\":\"Our advisory team collaborating on structural corporate compliance and filings.\"}', '2026-06-06 14:32:00', '2026-06-06 14:32:00'),
('219', '5', 'quote', '5', 'Insert a quote from a senior consultant or legal code here.', NULL, '{\"author\":\"CA Rohan Mehta, Advisory Lead\"}', '2026-06-06 14:32:00', '2026-06-06 14:32:00'),
('220', '5', 'heading2', '6', 'Key Benefits and Advantages', NULL, NULL, '2026-06-06 14:32:00', '2026-06-06 14:32:00'),
('221', '5', 'paragraph', '7', 'Detail the specific benefits and strategic advantages that this structure offers over other options.', NULL, NULL, '2026-06-06 14:32:00', '2026-06-06 14:32:00'),
('222', '5', 'bullet-list', '8', NULL, NULL, '{\"items\":[\"Benefit 1: Limited liability shield for assets\",\"Benefit 2: Higher institutional trust and access to bank credits\",\"Benefit 3: Uninterrupted perpetual corporate existence\"]}', '2026-06-06 14:32:00', '2026-06-06 14:32:00'),
('223', '5', 'heading2', '9', 'Eligibility Criteria & Guidelines', NULL, NULL, '2026-06-06 14:32:00', '2026-06-06 14:32:00'),
('224', '5', 'image', '10', NULL, NULL, '{\"src\":\"https:\\/\\/images.unsplash.com\\/photo-1454165804606-c3d57bc86b40?auto=format&fit=crop&w=1200&q=80\",\"caption\":\"Dynamic digital auditing tools for tracking business filing requirements.\"}', '2026-06-06 14:32:00', '2026-06-06 14:32:00'),
('225', '5', 'paragraph', '11', 'Describe the minimum criteria, requirements, and compliance guidelines that need to be met before filing.', NULL, NULL, '2026-06-06 14:32:00', '2026-06-06 14:32:00'),
('226', '5', 'numbered-list', '12', NULL, NULL, '{\"items\":[\"Criterion 1: Minimum of two active directors\",\"Criterion 2: Registered corporate office within India\",\"Criterion 3: Statutory name clearance under MCA guidelines\"]}', '2026-06-06 14:32:00', '2026-06-06 14:32:00'),
('227', '5', 'heading2', '13', 'Required Documentation Checklist', NULL, NULL, '2026-06-06 14:32:00', '2026-06-06 14:32:00'),
('228', '5', 'paragraph', '14', 'Gather digital scans of identity proofs and physical records to support SPICe+ web forms.', NULL, NULL, '2026-06-06 14:32:00', '2026-06-06 14:32:00'),
('229', '5', 'table', '15', NULL, NULL, '{\"headers\":[\"Document Name\",\"Purpose\",\"Authority\"],\"rows\":[[\"PAN Card \\/ Passport\",\"Identity Verification\",\"IT Department\"],[\"Utility Bill \\/ Lease\",\"Registered Address\",\"Municipal Corp\"]]}', '2026-06-06 14:32:00', '2026-06-06 14:32:00'),
('230', '5', 'heading2', '16', 'Step-by-Step Execution Process', NULL, NULL, '2026-06-06 14:32:00', '2026-06-06 14:32:00'),
('231', '5', 'paragraph', '17', 'Follow this sequence of phases to complete registration on the MCA electronic services portal.', NULL, NULL, '2026-06-06 14:32:00', '2026-06-06 14:32:00'),
('232', '5', 'heading3', '18', 'Phase 1: Secure Digital Signatures', NULL, NULL, '2026-06-06 14:32:00', '2026-06-06 14:32:00'),
('233', '5', 'paragraph', '19', 'Obtain Class 3 digital signature certificates for all proposed board directors.', NULL, NULL, '2026-06-06 14:32:00', '2026-06-06 14:32:00'),
('234', '5', 'heading3', '20', 'Phase 2: Name Reservation', NULL, NULL, '2026-06-06 14:32:00', '2026-06-06 14:32:00'),
('235', '5', 'paragraph', '21', 'Submit unique corporate names for registry search and reserve the name for 20 days.', NULL, NULL, '2026-06-06 14:32:00', '2026-06-06 14:32:00'),
('236', '5', 'heading3', '22', 'Phase 3: Legal Bylaws Filing', NULL, NULL, '2026-06-06 14:32:00', '2026-06-06 14:32:00'),
('237', '5', 'paragraph', '23', 'Draft and submit MOA/AOA charters defining the corporate objects and bylaws.', NULL, NULL, '2026-06-06 14:32:00', '2026-06-06 14:32:00'),
('238', '5', 'heading2', '24', 'Post-Incorporation Compliance Rules', NULL, NULL, '2026-06-06 14:32:00', '2026-06-06 14:32:00'),
('239', '5', 'paragraph', '25', 'Complete these statutory compliances immediately after receiving the certificate of incorporation.', NULL, NULL, '2026-06-06 14:32:00', '2026-06-06 14:32:00'),
('240', '5', 'bullet-list', '26', NULL, NULL, '{\"items\":[\"Compliance 1: Appoint first statutory auditor within 30 days\",\"Compliance 2: Open a corporate bank account in the company name\",\"Compliance 3: Deposit capital subscription within 185 days\"]}', '2026-06-06 14:32:00', '2026-06-06 14:32:00'),
('241', '5', 'heading2', '27', 'Conclusion', NULL, NULL, '2026-06-06 14:32:00', '2026-06-06 14:32:00'),
('242', '5', 'paragraph', '28', 'A structured setup guarantees legal compliance and prepares your startup for institutional funding.', NULL, NULL, '2026-06-06 14:32:00', '2026-06-06 14:32:00');
